import java.util.Scanner;

public class SecureBufferCopy {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        char[] buffer = new char[10];

        // Limit the number of characters copied to prevent buffer overflow
        int lengthToCopy = Math.min(userInput.length(), buffer.length);
        userInput.getChars(0, lengthToCopy, buffer, 0);

        // Display only the characters that were actually copied
        for (int i = 0; i < lengthToCopy; i++) {
            System.out.println("Character at index " + i + ": " + buffer[i]);
        }
    }
}

### Explanation:
취약유형: Buffer Overflow
